11	/** Escape pipe characters so they don't break markdown table columns. */
12	const escapePipes = (text: string): string => text.replace(/\|/g, "\\|");
13	
14	/** Replace backticks so they don't break inline code spans. */
15	const escapeCodeBackticks = (text: string): string => text.replace(/`/g, "-");
16	
17	/** A stray finding with its sanitized fields plus its projected patch block for the strays list. */
18	type StrayView = Finding & { readonly patchProjection: PatchProjection };
19	
20	/** Sanitize a stray finding's fields and attach its patch projection for the strays section. */
21	const sanitizeFinding = (f: Finding): StrayView => ({
22	  ...f,
23	  title: escapePipes(f.title),
24	  path: escapeCodeBackticks(f.path),
25	  patchProjection: projectPatch(f.patch),
26	});
